class OAuthClient {
    constructor(clientId, clientSecret, redirectUri) {
        this.clientId = clientId;
        this.clientSecret = clientSecret;
        this.redirectUri = redirectUri;
        this.accessToken = localStorage.getItem('accessToken');
        this.refreshToken = localStorage.getItem('refreshToken');
        this.tokenExpiresAt = localStorage.getItem('tokenExpiresAt') ? parseInt(localStorage.getItem('tokenExpiresAt')) : 0;

        if (this.accessToken && this.refreshToken) {
            this.scheduleTokenRefresh();
        }
    }

    async authorize() {
        const authUrl = `https://auth.example.com/oauth/authorize?response_type=code&client_id=${encodeURIComponent(this.clientId)}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=read%20write`;
        window.location.href = authUrl;
    }

    async handleCallback(code) {
        try {
            const response = await fetch('https://auth.example.com/oauth/token', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded'
                },
                body: new URLSearchParams({
                    grant_type: 'authorization_code',
                    code: code,
                    redirect_uri: this.redirectUri,
                    client_id: this.clientId,
                    client_secret: this.clientSecret
                })
            });

            const data = await response.json();
            this.accessToken = data.access_token;
            this.refreshToken = data.refresh_token;
            this.tokenExpiresAt = Date.now() + (data.expires_in * 1000);

            localStorage.setItem('accessToken', this.accessToken);
            localStorage.setItem('refreshToken', this.refreshToken);
            localStorage.setItem('tokenExpiresAt', this.tokenExpiresAt);

            this.scheduleTokenRefresh();
        } catch (error) {
            console.error('Error handling OAuth callback:', error);
        }
    }

    async refreshAccessToken() {
        try {
            const response = await fetch('https://auth.example.com/oauth/token', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded'
                },
                body: new URLSearchParams({
                    grant_type: 'refresh_token',
                    refresh_token: this.refreshToken,
                    client_id: this.clientId,
                    client_secret: this.clientSecret
                })
            });

            const data = await response.json();
            this.accessToken = data.access_token;
            this.tokenExpiresAt = Date.now() + (data.expires_in * 1000);

            localStorage.setItem('accessToken', this.accessToken);
            localStorage.setItem('tokenExpiresAt', this.tokenExpiresAt);
        } catch (error) {
            console.error('Error refreshing access token:', error);
        }
    }

    scheduleTokenRefresh() {
        const timeUntilExpiration = this.tokenExpiresAt - Date.now();
        if (timeUntilExpiration > 0) {
            setTimeout(() => this.refreshAccessToken(), timeUntilExpiration - 5000); // Refresh 5 seconds before expiration
        } else {
            console.error('Access token has already expired');
        }
    }

    async fetchResource(url, options = {}) {
        if (!this.accessToken) {
            throw new Error('No access token available');
        }

        const response = await fetch(url, {
            ...options,
            headers: {
                ...options.headers,
                'Authorization': `Bearer ${this.accessToken}`
            }
        });

        if (response.status === 401 && this.refreshToken) {
            await this.refreshAccessToken();
            return await fetch(url, options);
        }

        return response;
    }
}

